    var encryptVectors :- ParseJsonManifests.BuildEncryptTestVector(encryptManifest.keys, encryptManifest.jsonTests);
    var encryptTests :- ToEncryptTests(encryptManifest.keys, encryptVectors);
    var decryptVectors := TestEncrypts(encryptTests, encryptManifest.keys);
    var _ /* _v0 */ :- CompleteVectors.WriteDecryptManifest(op, encryptManifest.keys, decryptVectors);
    Time.PrintTimeSince(time);
    output := Success(());
  }

  method TestEncrypts(tests: seq<TestVectors.EncryptTest>, keys: KeyVectors.KeyVectorsClient) returns (output: seq<TestVectors.DecryptTestVector>)
    requires keys.ValidState()
    requires forall t: TestVectors.EncryptTest {:trigger t.cmm} {:trigger t in tests} | t in tests :: t.cmm.ValidState()
    modifies keys.Modifies, set t: TestVectors.EncryptTest, o: object {:trigger o in t.cmm.Modifies} | t in tests && o in t.cmm.Modifies :: o
    ensures keys.ValidState()
    ensures forall t: TestVectors.EncryptTest {:trigger t.cmm} {:trigger t in tests} | t in tests :: t.cmm.ValidState()
    decreases tests, keys
  {
    var hasFailure := false;
    print ""\n=================== Starting "", |tests|, "" Encrypt Tests =================== \n\n"";
    var decryptableTests: seq<(TestVectors.EncryptTest, Types.EncryptionMaterials)> := [];
    var time := Time.GetAbsoluteTime();
    for i: int := 0 to |tests|
      invariant forall t: TestVectors.EncryptTest {:trigger t.cmm} {:trigger t in tests} | t in tests :: t.cmm.ValidState()
    {
      var test := tests[i];
      var pass, maybeEncryptionMaterials := TestVectors.TestGetEncryptionMaterials(test);
      if pass && !test.vector.NegativeEncryptKeyringVector? {
        decryptableTests := decryptableTests + [(test, maybeEncryptionMaterials.value)];
      } else if !pass {
        hasFailure := true;
      }
    }
    var elapsed := Time.TimeSince(time);
    Time.PrintTimeLong(elapsed, ""TestEncrypts"", Some(LogFileName()));
    print ""\n=================== Completed "", |tests|, "" Encrypt Tests =================== \n\n"";
    expect !hasFailure, ""expectation violation"";
    output :- expect ToDecryptTestVectors(keys, decryptableTests);
  }

  method StartDecrypt(op: MplManifestOptions.ManifestOptions) returns (output: Result<(), string>)
    requires op.Decrypt?
    decreases op
  {
    var time := Time.GetAbsoluteTime();
    var decryptManifest :- GetManifest(op.manifestPath, ""manifest.json"");
    :- Need(decryptManifest.DecryptManifest?, ""Not a encrypt manifest"");
    var decryptVectors :- ParseJsonManifests.BuildDecryptTestVector(decryptManifest.keys, decryptManifest.jsonTests);
    var decryptTests :- ToDecryptTests(decryptManifest.keys, decryptVectors);
    TestDecrypts(decryptTests);
    Time.PrintTimeSince(time);
    output := Success(());
  }

  method TestDecrypts(tests: seq<TestVectors.DecryptTest>)
    requires forall t: TestVectors.DecryptTest {:trigger t.cmm} {:trigger t in tests} | t in tests :: t.cmm.ValidState()
    modifies set t: TestVectors.DecryptTest, o: object {:trigger o in t.cmm.Modifies} | t in tests && o in t.cmm.Modifies :: o
    ensures forall t: TestVectors.DecryptTest {:trigger t.cmm} {:trigger t in tests} | t in tests :: t.cmm.ValidState()
    decreases tests
  {
    print ""\n=================== Starting "", |tests|, "" Decrypt Tests =================== \n\n"";
    var hasFailure := false;
    var time := Time.GetAbsoluteTime();
    for i: int := 0 to |tests|
      invariant forall t: TestVectors.DecryptTest {:trigger t.cmm} {:trigger t in tests} | t in tests :: t.cmm.ValidState()
    {
      var pass := TestVectors.TestDecryptMaterials(tests[i]);
      if !pass {
        hasFailure := true;
      }
    }
    var elapsed := Time.TimeSince(time);
    Time.PrintTimeLong(elapsed, ""TestDecrypts"", Some(LogFileName()));
    print ""\n=================== Completed "", |tests|, "" Decrypt Tests =================== \n\n"";
    expect !hasFailure, ""expectation violation"";
  }

  method ToEncryptTests(keys: KeyVectors.KeyVectorsClient, encryptVectors: seq<TestVectors.EncryptTestVector>) returns (output: Result<seq<TestVectors.EncryptTest>, string>)
    requires keys.ValidState()
    modifies keys.Modifies
    ensures keys.ValidState()
    ensures output.Success? ==> true && forall t: TestVectors.EncryptTest {:trigger t.cmm} {:trigger t in output.value} | t in output.value :: t.cmm.ValidState() && fresh(t.cmm.Modifies)
    decreases keys, encryptVectors
  {
    var encryptTests: seq<TestVectors.EncryptTest> := [];
    for i: int := 0 to |encryptVectors|
      invariant forall t: TestVectors.EncryptTest {:trigger t.cmm} {:trigger t in encryptTests} | t in encryptTests :: t.cmm.ValidState() && fresh(t.cmm.Modifies)
    {
      var test :- TestVectors.ToEncryptTest(keys, encryptVectors[i]);
      encryptTests := encryptTests + [test];
    }
    return Success(encryptTests);
  }

  method ToDecryptTestVectors(keys: KeyVectors.KeyVectorsClient, tests: seq<(TestVectors.EncryptTest, Types.EncryptionMaterials)>) returns (output: Result<seq<TestVectors.DecryptTestVector>, string>)
    requires keys.ValidState()
    modifies keys.Modifies
    ensures keys.ValidState()
    decreases keys, tests
  {
    var successfulEncrypt := Seq.Filter((r: (TestVectors.EncryptTest, Types.EncryptionMaterials)) => r.0.vector.PositiveEncryptKeyringVector? || r.0.vector.PositiveEncryptNegativeDecryptKeyringVector?, tests);
    var decryptTestVectors: seq<TestVectors.DecryptTestVector> := [];
    for i: int := 0 to |successfulEncrypt| {
      var vector := TestVectors.EncryptTestToDecryptVector(successfulEncrypt[i].0, successfulEncrypt[i].1);
      decryptTestVectors := decryptTestVectors + [vector];
    }
    output := Success(decryptTestVectors);
  }

  method ToDecryptTests(keys: KeyVectors.KeyVectorsClient, vectors: seq<TestVectors.DecryptTestVector>) returns (output: Result<seq<TestVectors.DecryptTest>, string>)
    requires keys.ValidState()
    modifies keys.Modifies
    ensures keys.ValidState()
    ensures output.Success? ==> true && forall t: TestVectors.DecryptTest {:trigger t.cmm} {:trigger t in output.value} | t in output.value :: t.cmm.ValidState() && fresh(t.cmm.Modifies)
    decreases keys, vectors
  {
    var decryptTests: seq<TestVectors.DecryptTest> := [];
    for i: int := 0 to |vectors|
      invariant forall t: TestVectors.DecryptTest {:trigger t.cmm} {:trigger t in decryptTests} | t in decryptTests :: t.cmm.ValidState() && fresh(t.cmm.Modifies)
    {
      var test :- TestVectors.DecryptVectorToDecryptTest(keys, vectors[i]);
      decryptTests := decryptTests + [test];
    }
    return Success(decryptTests);
  }

  method GetManifest(manifestPath: string, manifestFileName: string) returns (manifestData: Result<ManifestData, string>)
    ensures manifestData.Success? ==> fresh(manifestData.value.keys.Modifies) && manifestData.value.keys.ValidState()
    decreases manifestPath, manifestFileName
  {
    var decryptManifestBytes :- FileIO.ReadBytesFromFile(manifestPath + manifestFileName);
    var manifestJson :- API.Deserialize(decryptManifestBytes).MapFailure((e: Errors.DeserializationError) => e.ToString());
    :- Need(manifestJson.Object?, ""Not a JSON object"");
    var manifest :- GetObject(""manifest"", manifestJson.obj);
    var version :- GetNat(""version"", manifest);
    var typ :- GetString(""type"", manifest);
    var keyManifestUri :- GetString(""keys"", manifestJson.obj);
    :- Need(""file://"" < keyManifestUri, ""Unexpected URI prefix"");
    var keyManifestPath := manifestPath + keyManifestUri[7..];
    var keys :- expect KeyVectors.KeyVectors(KeyVectorsTypes.KeyVectorsConfig(keyManifestPath := keyManifestPath));
    var jsonTests :- GetObject(""tests"", manifestJson.obj);
    match typ
    case {:split false} ""awses-mpl-decrypt"" =>
      var client :- Get(""client"", manifestJson.obj);
      manifestData := Success(DecryptManifest(version := version, keys := keys, client := client, jsonTests := jsonTests));
    case {:split false} ""awses-mpl-encrypt"" =>
      manifestData := Success(EncryptManifest(version := version, keys := keys, jsonTests := jsonTests));
    case {:split false} _ /* _v1 */ =>
      manifestData := Failure(""Unsupported manifest type:"" + typ);
  }

  import Types = AwsCryptographyMaterialProvidersTypes

  import opened Wrappers

  import AtomicPrimitives

  import TestVectors

  import FileIO

  import API = JSON.API

  import Values = JSON.Values

  import Errors = JSON.Errors

  import Seq

  import BoundedInts

  import opened JSONHelpers

  import ParseJsonManifests

  import KeyVectors

  import KeyVectorsTypes = AwsCryptographyMaterialProvidersTestVectorKeysTypes

  import MplManifestOptions

  import CompleteVectors

  import Time

  import OsLang

  datatype ManifestData = DecryptManifest(version: nat, keys: KeyVectors.KeyVectorsClient, client: Values.JSON, jsonTests: seq<(string, Values.JSON)>) | EncryptManifest(version: nat, keys: KeyVectors.KeyVectorsClient, jsonTests: seq<(string, Values.JSON)>)
}

module {:options ""-functionSyntax:4""} ParseJsonManifests {
  function BuildEncryptTestVector(keys: KeyVectors.KeyVectorsClient, obj: seq<(string, JSON)>): Result<seq<EncryptTestVector>, string>
    decreases keys, obj
  {
    if |obj| == 0 then
      Success([])
    else
      var tail: seq<EncryptTestVector> :- BuildEncryptTestVector(keys, obj[1..]); var encryptVector: EncryptTestVector :- ToEncryptTestVector(keys, obj[0].0, obj[0].1); Success([encryptVector] + tail)
  } by method {
    var i: nat := |obj|;
    var vectors := [];
    while i != 0
      invariant Success(vectors) == BuildEncryptTestVector(keys, obj[i..])
      decreases i
    {
      i := i - 1;
      var test := ToEncryptTestVector(keys, obj[i].0, obj[i].1);
      if test.Failure? {
        ghost var j := i;
        while j != 0
          invariant Failure(test.error) == BuildEncryptTestVector(keys, obj[j..])
          decreases j
        {
          j := j - 1;
        }
        return Failure(test.error);
      }
      vectors := [test.value] + vectors;
    }
    return Success(vectors);
  }

  function method ToEncryptTestVector(keys: KeyVectors.KeyVectorsClient, name: string, obj: JSON): Result<EncryptTestVector, string>
    decreases keys, name, obj
  {
    :- Need(obj.Object?, ""EncryptTestVector not an object""); var obj: seq<(string, JSON)> := obj.obj; var typString: string := ""type""; var typ: string :- GetString(typString, obj); var description: Option<string> := GetString(""description"", obj).ToOption(); var encryptionContextStrings: map<string, string> :- SmallObjectToStringStringMap(""encryptionContext"", obj); var encryptionContext: Types.EncryptionContext :- utf8EncodeMap(encryptionContextStrings); var algorithmSuite: Types.AlgorithmSuiteInfo :- GetAlgorithmSuiteInfo(obj); var requiredEncryptionContextKeys: Option<seq<UTF8.ValidUTF8Bytes>> :- GetRequiredEncryptionContextKeys(obj); var reproducedEncryptionContext: Option<map<UTF8.ValidUTF8Bytes, UTF8.ValidUTF8Bytes>> :- GetReproducedEncryptionContext(obj); var commitmentPolicy: Types.CommitmentPolicy := CompleteVectors.AllAlgorithmSuites.GetCompatibleCommitmentPolicy(algorithmSuite); var maxPlaintextLength: Option<BoundedInts.int64> := GetPositiveLong(""maxPlaintextLength"", obj).ToOption(); match typ case ""positive-keyring"" => (var encryptKeyDescription: KeyVectorsTypes.KeyDescription :- GetKeyDescription(keys, ""encryptKeyDescription"", obj); var decryptKeyDescription: KeyVectorsTypes.KeyDescription :- GetKeyDescription(keys, ""decryptKeyDescription"", obj); Success(PositiveEncryptKeyringVector(name := name, description := description, encryptionContext := encryptionContext, commitmentPolicy := commitmentPolicy, algorithmSuite := algorithmSuite, maxPlaintextLength := maxPlaintextLength, requiredEncryptionContextKeys := requiredEncryptionContextKeys, encryptDescription := encryptKeyDescription, decryptDescription := decryptKeyDescription, reproducedEncryptionContext := reproducedEncryptionContext))) case ""negative-encrypt-keyring"" => (var keyDescription: KeyVectorsTypes.KeyDescription :- GetKeyDescription(keys, ""keyDescription"", obj); var errorDescription: string :- GetString(""errorDescription"", obj); :- Need(reproducedEncryptionContext.None?, ""reproducedEncryptionContext not supported""); Success(NegativeEncryptKeyringVector(name := name, description := description, encryptionContext := encryptionContext, commitmentPolicy := commitmentPolicy, algorithmSuite := algorithmSuite, maxPlaintextLength := maxPlaintextLength, requiredEncryptionContextKeys := requiredEncryptionContextKeys, errorDescription := errorDescription, keyDescription := keyDescription))) case ""negative-decrypt-keyring"" => (var encryptKeyDescription: KeyVectorsTypes.KeyDescription :- GetKeyDescription(keys, ""encryptKeyDescription"", obj); var decryptKeyDescription: KeyVectorsTypes.KeyDescription :- GetKeyDescription(keys, ""decryptKeyDescription"", obj); var decryptErrorDescription: string :- GetString(""decryptErrorDescription"", obj); Success(PositiveEncryptNegativeDecryptKeyringVector(name := name, description := description, decryptErrorDescription := decryptErrorDescription, encryptionContext := encryptionContext, commitmentPolicy := commitmentPolicy, algorithmSuite := algorithmSuite, maxPlaintextLength := maxPlaintextLength, requiredEncryptionContextKeys := requiredEncryptionContextKeys, encryptDescription := encryptKeyDescription, decryptDescription := decryptKeyDescription, reproducedEncryptionContext := reproducedEncryptionContext))) case _ /* _v0 */ => Failure(""Unsupported EncryptTestVector type:"" + typ)
  }

  function method GetKeyDescription(keyVectorClient: KeyVectors.KeyVectorsClient, key: string, obj: seq<(string, JSON)>): Result<KeyVectorsTypes.KeyDescription, string>
    decreases keyVectorClient, key, obj
  {
    var keyDescriptionObject: Values.JSON :- Get(key, obj); var descriptionStr: seq<byte> :- API.Serialize(keyDescriptionObject).MapFailure((e: Errors.SerializationError) => e.ToString()); var keyDescriptionOutput: GetKeyDescriptionOutput :- keyVectorClient.GetKeyDescription(KeyVectorsTypes.GetKeyDescriptionInput(json := descriptionStr)).MapFailure(ErrorToString); Success(keyDescriptionOutput.keyDescription)
  }

  function method GetAlgorithmSuiteInfo(obj: seq<(string, JSON)>): Result<Types.AlgorithmSuiteInfo, string>
    decreases obj
  {
    var algorithmSuiteHex: string :- GetString(""algorithmSuiteId"", obj); :- Need(HexStrings.IsLooseHexString(algorithmSuiteHex), ""Not hex encoded binary""); var binaryId: seq<uint8> := HexStrings.FromHexString(algorithmSuiteHex); AlgorithmSuites.GetAlgorithmSuiteInfo(binaryId).MapFailure((e: Error) => ""Invalid Suite:"" + algorithmSuiteHex)
  }

  function method GetRequiredEncryptionContextKeys(obj: seq<(string, JSON)>): Result<Option<seq<UTF8.ValidUTF8Bytes>>, string>
    decreases obj
  {
    var keysAsStrings: Option<seq<string>> := GetArrayString(""requiredEncryptionContextKeys"", obj).ToOption();
    match keysAsStrings
    case Some(s) =>
      var k: seq<Types.Utf8Bytes> :- utf8EncodeSeq(keysAsStrings.value); Success(Some(k))
    case None() =>
      Success(None())
  }

  function method GetReproducedEncryptionContext(obj: seq<(string, JSON)>): Result<Option<map<UTF8.ValidUTF8Bytes, UTF8.ValidUTF8Bytes>>, string>
    decreases obj
  {
    var reproducedEncryptionContextStrings: Option<map<string, string>> :- GetOptionalSmallObjectToStringStringMap(""reproducedEncryptionContext"", obj); match reproducedEncryptionContextStrings case Some(r) => (var e: Types.EncryptionContext :- utf8EncodeMap(r); Success(Some(e))) case None() => Success(None())
  }

  function method ErrorToString(e: KeyVectorsTypes.Error): string
    decreases e
  {
    match e
    case KeyVectorException(message) =>
      message
    case AwsCryptographyMaterialProviders(mplError) =>
      (match mplError
      case AwsCryptographicMaterialProvidersException(message) =>
        message
      case _ /* _v1 */ =>
        ""Unmapped AwsCryptographyMaterialProviders"")
    case _ /* _v2 */ =>
      ""Unmapped KeyVectorException""
  }

  function BuildDecryptTestVector(keys: KeyVectors.KeyVectorsClient, obj: seq<(string, JSON)>): Result<seq<DecryptTestVector>, string>
    decreases keys, obj
  {
    if |obj| == 0 then
      Success([])
    else
      var tail: seq<DecryptTestVector> :- BuildDecryptTestVector(keys, obj[1..]); var encryptVector: DecryptTestVector :- ToDecryptTestVector(keys, obj[0].0, obj[0].1); Success([encryptVector] + tail)
  } by method {
    var i: nat := |obj|;
    var vectors := [];
    while i != 0
      invariant Success(vectors) == BuildDecryptTestVector(keys, obj[i..])
      decreases i
    {
      i := i - 1;
      var test := ToDecryptTestVector(keys, obj[i].0, obj[i].1);
      if test.Failure? {
        ghost var j := i;
        while j != 0
          invariant Failure(test.error) == BuildDecryptTestVector(keys, obj[j..])
          decreases j
        {
          j := j - 1;
        }
        return Failure(test.error);
      }
      vectors := [test.value] + vectors;
    }
    return Success(vectors);
  }

  function printJson(j: seq<(string, JSON)>): ()
    decreases j
  {
    ()
  } by method {
    print j, ""\n"", ""\n"";
    return ();
  }

  function method GetEncryptedDataKeys(obj: seq<(string, JSON)>): Result<Types.EncryptedDataKeyList, string>
    decreases obj
  {
    var encryptedDataKeysJson: seq<JSON> :- GetArray(""encryptedDataKeys"", obj); Seq.MapWithResult(GetEncryptedDataKey, encryptedDataKeysJson)
  }

  function method GetEncryptedDataKey(json: JSON): Result<Types.EncryptedDataKey, string>
    decreases json
  {
    :- Need(json.Object?, ""Encrypted data key is not an object""); var keyProviderId: string :- GetString(""keyProviderId"", json.obj); var keyProviderInfo: string :- GetString(""keyProviderInfo"", json.obj); var ciphertext: string :- GetString(""ciphertext"", json.obj); var keyProviderId: ValidUTF8Bytes :- UTF8.Encode(keyProviderId); var keyProviderInfo: seq<uint8> :- Base64.Decode(keyProviderInfo); var ciphertext: seq<uint8> :- Base64.Decode(ciphertext); Success(Types.EncryptedDataKey(keyProviderId := keyProviderId, keyProviderInfo := keyProviderInfo, ciphertext := ciphertext))
  }

  function method GetExpectedResult(obj: seq<(string, JSON)>): Result<DecryptResult, string>
    decreases obj
  {
    var result: seq<(string, JSON)> :- GetObject(""result"", obj); var plaintextDataKey: Option<string> :- GetOptionalString(""plaintextDataKey"", result); var symmetricSigningKey: Option<string> :- GetOptionalString(""symmetricSigningKey"", result); var requiredEncryptionContextKeys: seq<string> :- GetArrayString(""requiredEncryptionContextKeys"", result); var plaintextDataKey: Option<seq<uint8>> :- if plaintextDataKey.Some? then var p: seq<uint8> :- Base64.Decode(plaintextDataKey.value); Success(Some(p)) else Success(None); var symmetricSigningKey: Option<seq<uint8>> :- if symmetricSigningKey.Some? then var p: seq<uint8> :- Base64.Decode(symmetricSigningKey.value); Success(Some(p)) else Success(None); var requiredEncryptionContextKeys: seq<Types.Utf8Bytes> :- utf8EncodeSeq(requiredEncryptionContextKeys); Success(DecryptResult(plaintextDataKey := plaintextDataKey, symmetricSigningKey := symmetricSigningKey, requiredEncryptionContextKeys := requiredEncryptionContextKeys))
  }

  function method ToDecryptTestVector(keys: KeyVectors.KeyVectorsClient, name: string, json: JSON): Result<DecryptTestVector, string>
    decreases keys, name, json
  {
    :- Need(json.Object?, ""DecryptTestVector not an object""); var obj: seq<(string, JSON)> := json.obj; var typString: string := ""type""; var typ: string :- GetString(typString, obj); var description: Option<string> :- GetOptionalString(""description"", obj); var encryptionContextStrings: map<string, string> :- SmallObjectToStringStringMap(""encryptionContext"", obj); var encryptionContext: Types.EncryptionContext :- utf8EncodeMap(encryptionContextStrings); var algorithmSuite: Types.AlgorithmSuiteInfo :- GetAlgorithmSuiteInfo(obj); var reproducedEncryptionContext: Option<map<UTF8.ValidUTF8Bytes, UTF8.ValidUTF8Bytes>> :- GetReproducedEncryptionContext(obj); var commitmentPolicy: Types.CommitmentPolicy := CompleteVectors.AllAlgorithmSuites.GetCompatibleCommitmentPolicy(algorithmSuite); var keyDescription: KeyVectorsTypes.KeyDescription :- GetKeyDescription(keys, ""keyDescription"", obj); var encryptedDataKeys: Types.EncryptedDataKeyList :- GetEncryptedDataKeys(obj); match typ case ""positive-keyring"" => (var expectedResult: DecryptResult :- GetExpectedResult(obj); Success(PositiveDecryptKeyringTest(name := name, description := description, encryptionContext := encryptionContext, commitmentPolicy := commitmentPolicy, algorithmSuite := algorithmSuite, keyDescription := keyDescription, encryptedDataKeys := encryptedDataKeys, expectedResult := expectedResult, reproducedEncryptionContext := reproducedEncryptionContext))) case ""negative-keyring"" => (var errorDescription: string :- GetString(""errorDescription"", obj); Success(NegativeDecryptKeyringTest(name := name, description := description, encryptionContext := encryptionContext, commitmentPolicy := commitmentPolicy, algorithmSuite := algorithmSuite, errorDescription := errorDescription, encryptedDataKeys := encryptedDataKeys, keyDescription := keyDescription, reproducedEncryptionContext := reproducedEncryptionContext))) case _ /* _v3 */ => Failure(""Unsupported DecryptTestVector type:"" + typ)
  }

